// Function to calculate the factorial of a number
function factorial(x) {
    let result = 1;
    for (let i = 1; i <= x; i++) {
        result *= i;
    }
    return result;
}

// Assign a concrete value to x
const x = 7;

// Calculate the factorial
const fact = factorial(x);

// Output the result
console.log("The factorial of " + x + " is " + fact);

